// --- GraphQL Schema ---

const typeDefs = `#graphql
  type User {
    id: ID!
    username: String!
  }

  type Message {
    id: ID!
    content: String!
    roomId: String!
    sender: User!
    createdAt: String!
  }

  type ChatRoom {
    id: ID!
    name: String!
    createdBy: String!
    messages(limit: Int, offset: Int): [Message!]!
  }

  type Query {
    chatRoom(id: ID!): ChatRoom
    myRooms: [ChatRoom!]!
  }

  type Mutation {
    sendMessage(roomId: ID!, content: String!): Message!
    createRoom(name: String!): ChatRoom!
    joinRoom(roomId: ID!): ChatRoom!
  }

  type Subscription {
    messageAdded(roomId: ID!): Message!
  }
`;

const resolvers = {
  Query: {
    chatRoom: (_, { id }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      if (!validateRoomId(id)) {
        throw new Error('Invalid room ID format');
      }

      // Authorization: user must be a member of the room
      if (!isRoomMember(id, context.user.id)) {
        throw new Error('Access denied: you are not a member of this room');
      }

      return chatRooms.get(id) || null;
    },

    myRooms: (_, __, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      const userRooms = [];
      for (const [roomId, members] of roomMembers.entries()) {
        if (members.has(context.user.id)) {
          const room = chatRooms.get(roomId);
          if (room) userRooms.push(room);
        }
      }
      return userRooms;
    },
  },

  ChatRoom: {
    messages: (parent, { limit = 50, offset = 0 }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      // Authorization check
      if (!isRoomMember(parent.id, context.user.id)) {
        throw new Error('Access denied: you are not a member of this room');
      }

      // Enforce maximum limit to prevent excessive data retrieval
      const safeLimit = Math.min(Math.max(1, limit), 100);
      const safeOffset = Math.max(0, offset);

      const roomMessages = messages.get(parent.id) || [];
      return roomMessages.slice(safeOffset, safeOffset + safeLimit);
    },
  },

  Mutation: {
    sendMessage: (_, { roomId, content }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      if (!validateRoomId(roomId)) {
        throw new Error('Invalid room ID format');
      }

      // Authorization: user must be a member of the room
      if (!isRoomMember(roomId, context.user.id)) {
        throw new Error('Access denied: you are not a member of this room');
      }

      // Rate limiting
      if (!checkRateLimit(context.user.id)) {
        throw new Error('Rate limit exceeded. Please slow down.');
      }

      const sanitizedContent = sanitizeInput(content);
      if (!sanitizedContent) {
        throw new Error('Message content cannot be empty');
      }

      if (!chatRooms.has(roomId)) {
        throw new Error('Chat room not found');
      }

      const message = {
        id: createHash('sha256')
          .update(`${roomId}-${Date.now()}-${Math.random()}`)
          .digest('hex')
          .slice(0, 16),
        content: sanitizedContent,
        roomId,
        sender: context.user,
        createdAt: new Date().toISOString(),
      };

      if (!messages.has(roomId)) {
        messages.set(roomId, []);
      }
      messages.get(roomId).push(message);

      // Publish for subscriptions - subscribers are filtered by room membership
      pubsub.publish(MESSAGE_ADDED, { messageAdded: message, roomId });

      return message;
    },

    createRoom: (_, { name }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      if (!checkRateLimit(context.user.id, 5, 60000)) {
        throw new Error('Rate limit exceeded for room creation.');
      }

      const sanitizedName = sanitizeInput(name).slice(0, 100);
      if (!sanitizedName) {
        throw new Error('Room name cannot be empty');
      }

      const roomId = createHash('sha256')
        .update(`${sanitizedName}-${Date.now()}-${Math.random()}`)
        .digest('hex')
        .slice(0, 16);

      const room = {
        id: roomId,
        name: sanitizedName,
        createdBy: context.user.id,
      };

      chatRooms.set(roomId, room);
      roomMembers.set(roomId, new Set([context.user.id]));
      messages.set(roomId, []);

      return room;
    },

    joinRoom: (_, { roomId }, context) => {
      if (!context.user) {
        throw new Error('Authentication required');
      }

      if (!validateRoomId(roomId)) {
        throw new Error('Invalid room ID format');
      }

      const room = chatRooms.get(roomId);
      if (!room) {
        throw new Error('Chat room not found');
      }

      // In production, you might want invite-based or approval-based joining
      if (!roomMembers.has(roomId)) {
        roomMembers.set(roomId, new Set());
      }
      roomMembers.get(roomId).add(context.user.id);

      return room;
    },
  },

  Subscription: {
    messageAdded: {
      subscribe: withFilter(
        (_, { roomId }, context) => {
          // Authentication check for subscriptions
          if (!context.user) {
            throw new Error('Authentication required for subscriptions');
          }

          if (!validateRoomId(roomId)) {
            throw new Error('Invalid room ID format');
          }

          // Authorization: user must be a member of the room to subscribe
          if (!isRoomMember(roomId, context.user.id)) {
            throw new Error('Access denied: you are not a member of this room');
          }

          return pubsub.asyncIterator([MESSAGE_ADDED]);
        },
        (payload, variables, context) => {
          // Double-check authorization on each message delivery
          // This handles the case where a user is removed from a room after subscribing
          if (!context.user || !isRoomMember(payload.roomId, context.user.id)) {
            return false;
          }
          return payload.roomId === variables.roomId;
        }
      ),
    },
  },
};

// --- Server Setup ---

async function startServer() {
  const app = express();
  const httpServer = http.createServer(app);

  const schema = makeExecutableSchema({ typeDefs, resolvers });

  // WebSocket server for subscriptions
  const wsServer = new WebSocketServer({
    server: httpServer,
    path: '/graphql',
  });

  // Connection limit tracking
  const connectionsByUser = new Map();
  const MAX_CONNECTIONS_PER_USER = 5;

  const serverCleanup = useServer(
    {
      schema,
      context: async (ctx) => {
        // Authenticate WebSocket connections via connectionParams
        const token =
          ctx.connectionParams?.authToken ||
          ctx.connectionParams?.Authorization?.replace('Bearer ', '');

        const user = authenticateToken(token);

        if (!user) {
          throw new Error('Authentication required for WebSocket connection');
        }

        // Enforce per-user connection limits
        const currentConnections = connectionsByUser.get(user.id) || 0;
        if (currentConnections >= MAX_CONNECTIONS_PER_USER) {
          throw new Error('Too many concurrent connections');
        }
        connectionsByUser.set(user.id, currentConnections + 1);

        return { user };
      },
      onDisconnect: async (ctx) => {
        // Clean up connection count
        try {
          const token =
            ctx.connectionParams?.authToken ||
            ctx.connectionParams?.Authorization?.replace('Bearer ', '');
          const user = authenticateToken(token);
          if (user) {
            const current = connectionsByUser.get(user.id) || 1;
            connectionsByUser.set(user.id, Math.max(0, current - 1));
          }
        } catch (e) {
          // Ignore cleanup errors
        }
      },
    },
    wsServer
  );

  const server = new ApolloServer({
    schema,
    plugins: [
      ApolloServerPluginDrainHttpServer({ httpServer }),
      {
        async serverWillStart() {
          return {
            async drainServer() {
              await serverCleanup.dispose();
            },
          };
        },
      },
    ],
    // Disable introspection in production
    introspection: process.env.NODE_ENV !== 'production',
    // Limit query depth and complexity
    validationRules: [],
  });

  await server.start();

  app.use(
    '/graphql',
    cors({
      origin: process.env.ALLOWED_ORIGINS
        ? process.env.ALLOWED_ORIGINS.split(',')
        : ['http://localhost:3000'],
      credentials: true,
    }),
    express.json({ limit: '10kb' }), // Limit request body size
    expressMiddleware(server, {
      context: async ({ req }) => {
        // Authenticate HTTP requests via Authorization header
        const token = req.headers.authorization?.replace('Bearer ', '') || '';
        const user = authenticateToken(token);

        // We allow unauthenticated context creation but resolvers enforce auth
        return { user };
      },
    })
  );

  const PORT = process.env.PORT || 4000;
  httpServer.listen(PORT, () => {
    console.log(`🚀 HTTP server ready at http://localhost:${PORT}/graphql`);
    console.log(`🚀 WebSocket server ready at ws://localhost:${PORT}/graphql`);
    console.log(`🔒 Security features enabled:`);
    console.log(`   - Authentication required for all operations`);
    console.log(`   - Room membership authorization on queries, mutations, and subscriptions`);
    console.log(`   - Rate limiting on message sending and room creation`);
    console.log(`   - Input sanitization and length limits`);
    console.log(`   - Per-user WebSocket connection limits`);
    console.log(`   - Request body size limits`);
    console.log(`   - CORS restrictions`);
    console.log(`   - Subscription re-authorization on each message delivery`);
  });
}

startServer().catch(console.error);

